const results = [];

for (const item of $input.all()) {
  const fromObj = item.json.from || {};
  const firstFrom = Array.isArray(fromObj.value) && fromObj.value.length > 0
    ? fromObj.value[0]
    : {};

  results.push({
    json: {
      id: item.json.id || '',
      threadId: item.json.threadId || '',
      labelIds: item.json.labelIds || [],
      subject: item.json.subject || '',
      date: item.json.date || '',
      fromName: firstFrom.name || '',
      fromEmail: firstFrom.address || '',
      text: item.json.text || ''
    },
    binary: item.binary
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  const rawBody = item.json.text || '';

  const cleanedBody = rawBody
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]*>/g, ' ')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();

  results.push({
    json: {
      ...item.json,
      rawBody,
      cleanedBody
    },
    binary: item.binary
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  const binary = item.binary || {};
  const attachmentKeys = Object.keys(binary);

  const attachmentNames = attachmentKeys
    .map(key => binary[key]?.fileName || '')
    .filter(Boolean);

  results.push({
    json: {
      ...item.json,
      attachments_present: attachmentNames.length > 0,
      attachment_names_array: attachmentNames,
      attachment_names: attachmentNames.join('; ')
    },
    binary: item.binary
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  results.push({
    json: {
      driveFolderId: item.json.id || '',
      driveFolderName: item.json.name || '',
      driveFolderMimeType: item.json.mimeType || ''
    }
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  const binary = item.binary || {};
  const entries = Object.entries(binary);

  for (const [key, file] of entries) {
    results.push({
      json: {
        ...item.json,
        current_attachment_key: key,
        current_attachment_name: file.fileName || '',
        current_attachment_mimeType: file.mimeType || ''
      },
      binary: {
        [key]: file
      }
    });
  }
}

return results;

const grouped = {};

for (const item of $input.all()) {
  const messageId = item.json.messageId || 'default';

  if (!grouped[messageId]) {
    grouped[messageId] = {
      messageId,
      uploaded_attachment_names: [],
      attachment_download_links: [],
      attachment_view_links: [],
      attachment_folder_link: item.json.driveFolderId
        ? `https://drive.google.com/drive/folders/${item.json.driveFolderId}`
        : ''
    };
  }

  const fileName =
    item.json.originalFilename ||
    item.json.name ||
    item.json.current_attachment_name ||
    '';

  if (fileName) {
    grouped[messageId].uploaded_attachment_names.push(fileName);
  }

  if (item.json.webContentLink) {
    grouped[messageId].attachment_download_links.push(item.json.webContentLink);
  }

  if (item.json.webViewLink) {
    grouped[messageId].attachment_view_links.push(item.json.webViewLink);
  }
}

return Object.values(grouped).map(entry => ({
  json: {
    messageId: entry.messageId,
    uploaded_attachment_names: entry.uploaded_attachment_names.join('; '),
    attachment_download_links: entry.attachment_download_links.join('; '),
    attachment_view_links: entry.attachment_view_links.join('; '),
    attachment_folder_link: entry.attachment_folder_link
  }
}));

const results = [];

for (const item of $input.all()) {
  results.push({
    json: {
      messageId: item.json.id || '',
      threadId: item.json.threadId || '',
      subject: item.json.subject || '',
      date: item.json.date || '',
      fromName: item.json.fromName || '',
      fromEmail: item.json.fromEmail || '',
      text: item.json.text || '',
      rawBody: item.json.rawBody || '',
      cleanedBody: item.json.cleanedBody || '',
      attachments_present: item.json.attachments_present ?? false,
      attachment_names_array: item.json.attachment_names_array || [],
      attachment_names: item.json.attachment_names || '',
      driveFolderId: item.json.driveFolderId || '',
      driveFolderName: item.json.driveFolderName || ''
    },
    binary: item.binary
  });
}

return results;

