const results = [];

for (const item of $input.all()) {
  const attachmentNames =
    item.json.uploaded_attachment_names ||
    item.json.attachment_names ||
    '';

  const attachmentDownloadLinks =
    item.json.attachment_download_links || '';

  const attachmentViewLinks =
    item.json.attachment_view_links || '';

  const attachmentFolderLink =
    item.json.attachment_folder_link || '';

  const attachmentsTextForAI = item.json.attachments_present
    ? `Yes.
Attachment names: ${attachmentNames || 'attached files'}.
Attachment download links: ${attachmentDownloadLinks || 'N/A'}.
Attachment view links: ${attachmentViewLinks || 'N/A'}.
Attachment folder link: ${attachmentFolderLink || 'N/A'}.`
    : 'No attachments.';

  results.push({
    json: {
      ...item.json,
      attachmentsTextForAI
    }
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  results.push({
    json: {
      ...item.json,
      uploaded_attachment_names: '',
      attachment_download_links: '',
      attachment_view_links: '',
      attachment_folder_link: ''
    }
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  const raw = item.json.output || '';

  let e;
  try {
    e = JSON.parse(raw);
  } catch (err) {
    throw new Error('Invalid JSON from AI output: ' + raw);
  }

  const confidence = Number(e.confidence_score ?? 0);

  const attachmentNames = Array.isArray(e.attachment_names)
    ? e.attachment_names.join('; ')
    : (e.attachment_names || item.json.uploaded_attachment_names || item.json.attachment_names || '');

  const attachmentDownloadLinks = Array.isArray(e.attachment_download_links)
    ? e.attachment_download_links.join('; ')
    : (e.attachment_download_links || item.json.attachment_download_links || '');

  const attachmentViewLinks = Array.isArray(e.attachment_view_links)
    ? e.attachment_view_links.join('; ')
    : (e.attachment_view_links || item.json.attachment_view_links || '');

  const attachmentFolderLink =
    e.attachment_folder_link || item.json.attachment_folder_link || '';

  results.push({
    json: {
      customer_name: e.customer_name || '',
      customer_email: e.customer_email || item.json.fromEmail || '',
      company_name: e.company_name || '',
      job_title: e.job_title || '',
      subject: e.subject || item.json.subject || '',
      product_type: e.product_type || '',
      item_name: e.item_name || '',
      quantity: e.quantity ?? '',
      length: e.dimensions?.length ?? '',
      width: e.dimensions?.width ?? '',
      height: e.dimensions?.height ?? '',
      unit: e.dimensions?.unit || 'mm',
      use_case: e.use_case || '',
      requirements: Array.isArray(e.requirements) ? e.requirements.join('; ') : '',
      timeline: e.timeline || '',
      attachments_present: e.attachments_present ?? item.json.attachments_present ?? false,
      attachment_names: attachmentNames,
      attachment_download_links: attachmentDownloadLinks,
      attachment_view_links: attachmentViewLinks,
      attachment_folder_link: attachmentFolderLink,
      summary: e.summary || '',
      missing_information: Array.isArray(e.missing_information) ? e.missing_information.join('; ') : '',
      confidence_score: confidence,
      status: confidence >= 0.75 ? 'New' : 'Review Required',
      processed_at: new Date().toISOString()
    }
  });
}

return results;

const out = [];

for (const item of $input.all()) {
  const j = item.json || {};
  const b = item.binary || {};

  const subject = j.subject || "";
  const fromObj = j.from || {};
  const firstFrom = Array.isArray(fromObj.value) && fromObj.value.length > 0 ? fromObj.value[0] : {};
  const fromLine = firstFrom.address
    ? (firstFrom.name ? `${firstFrom.name} <${firstFrom.address}>` : firstFrom.address)
    : "";

  const body = j.text || j.textPlain || j.snippet || "";

  const email_text = [
    subject ? `Subject: ${subject}` : "",
    fromLine ? `From: ${fromLine}` : "",
    "",
    body,
  ].filter(Boolean).join("\n");

  const images = [];
  for (const key of Object.keys(b)) {
    const meta = b[key];
    const mime = meta.mimeType || "application/octet-stream";
    if (!mime.startsWith("image/")) continue;

    // This is the important part for filesystem-v2
    const base64Data = await this.helpers.getBinaryDataBuffer(0, key);
    images.push({
      filename: meta.fileName || key,
      mime_type: mime,
      base64: base64Data.toString("base64"),
    });
  }

  out.push({ json: { email_text, images } });
}

return out;
